test('workspace API calls include platforms=google_ads', async ({ page }) => {
  const requests: string[] = [];
  page.on('request', req => { if (req.url().includes('/analytics/google-ads/')) requests.push(req.url()); });
  await page.goto('/dashboards/google-ads');
  await page.waitForTimeout(500);
  requests.forEach(url => expect(url).toContain('platforms=google_ads'));
});

